import { env } from '@nordic/env';
import { getReq } from '@meli/server-context';

import { CRITICAL_COOKIE_SEPARATOR } from './constants';
import { getCookiePath } from './utils';

export type CriticalCssStore = {
  path?: string;
  name: string;
  values: Set<string>;
};

export function createCriticalCssStore(path?: string): CriticalCssStore {
  const cookieName = `c_${env.APP_NAME_HASH}`;
  const cookieValue = getReq().cookies[cookieName];
  const currentValues = cookieValue?.split(CRITICAL_COOKIE_SEPARATOR);

  return {
    name: cookieName,
    path: path || getCookiePath(),
    values: currentValues?.includes(env.VERSION)
      ? new Set(currentValues)
      : new Set(),
  };
}
